import React, { useState, useRef, useEffect, useCallback } from 'react';
import { Message, AppStatus } from './types';
import Logo from './components/Logo';
import { getGeminiChatResponse, generateSpeech } from './services/geminiService';

const App: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [isMuted, setIsMuted] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);

  // Initialize Speech Recognition
  const [recognition, setRecognition] = useState<any>(null);

  useEffect(() => {
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
      const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
      const recog = new SpeechRecognition();
      recog.continuous = false;
      recog.interimResults = false;
      recog.lang = 'en-US';

      recog.onstart = () => setStatus(AppStatus.LISTENING);
      recog.onresult = (event: any) => {
        const transcript = event.results[0][0].transcript;
        handleSendMessage(transcript);
      };
      recog.onerror = () => setStatus(AppStatus.IDLE);
      recog.onend = () => {
        if (status === AppStatus.LISTENING) setStatus(AppStatus.IDLE);
      };
      setRecognition(recog);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const scrollToBottom = () => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({
        top: scrollRef.current.scrollHeight,
        behavior: 'smooth',
      });
    }
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, status]);

  const decodeAudio = async (base64: string) => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }
    const ctx = audioContextRef.current;

    // Manual Base64 decode
    const binaryString = atob(base64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }

    // Raw PCM decode
    const dataInt16 = new Int16Array(bytes.buffer);
    const frameCount = dataInt16.length;
    const buffer = ctx.createBuffer(1, frameCount, 24000);
    const channelData = buffer.getChannelData(0);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i] / 32768.0;
    }
    return buffer;
  };

  const playSpeech = async (text: string) => {
    if (isMuted) return;
    setStatus(AppStatus.SPEAKING);
    const audioData = await generateSpeech(text);
    if (audioData) {
      const buffer = await decodeAudio(audioData);
      const ctx = audioContextRef.current!;
      const source = ctx.createBufferSource();
      source.buffer = buffer;
      source.connect(ctx.destination);
      source.onended = () => setStatus(AppStatus.IDLE);
      source.start();
    } else {
      setStatus(AppStatus.IDLE);
    }
  };

  const handleSendMessage = async (text: string = inputValue) => {
    if (!text.trim()) return;

    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: text,
      timestamp: Date.now(),
    };

    setMessages(prev => [...prev, userMsg]);
    setInputValue('');
    setStatus(AppStatus.THINKING);

    const history = messages.slice(-6).map(m => ({ role: m.role, content: m.content }));
    const responseText = await getGeminiChatResponse(text, history);

    const botMsg: Message = {
      id: (Date.now() + 1).toString(),
      role: 'assistant',
      content: responseText || "My systems encountered an error.",
      timestamp: Date.now(),
    };

    setMessages(prev => [...prev, botMsg]);
    await playSpeech(botMsg.content);
  };

  const toggleVoiceInput = () => {
    if (status === AppStatus.LISTENING) {
      recognition?.stop();
    } else {
      recognition?.start();
    }
  };

  return (
    <div className="flex flex-col h-screen max-w-md mx-auto relative bg-[#050505] shadow-2xl overflow-hidden border-x border-white/5">
      {/* Dynamic Background Elements */}
      <div className="absolute inset-0 z-0 pointer-events-none opacity-20">
        <div className="absolute top-1/4 -left-20 w-64 h-64 bg-cyan-600 rounded-full blur-[100px]"></div>
        <div className="absolute bottom-1/4 -right-20 w-64 h-64 bg-purple-600 rounded-full blur-[100px]"></div>
        <div className="absolute top-0 left-0 w-full h-full bg-[radial-gradient(#111_1px,transparent_1px)] bg-[size:40px_40px]"></div>
      </div>

      {/* Header */}
      <header className="relative z-10 px-4 pt-4 shrink-0">
        <Logo />
      </header>

      {/* Chat Area */}
      <main 
        ref={scrollRef}
        className="flex-1 overflow-y-auto px-4 py-6 relative z-10 space-y-6"
      >
        {messages.length === 0 && (
          <div className="h-full flex flex-col items-center justify-center opacity-50 space-y-4 text-center px-8">
            <div className="w-16 h-16 rounded-full border border-cyan-500/30 flex items-center justify-center animate-pulse">
               <svg className="w-8 h-8 text-cyan-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                 <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z" />
               </svg>
            </div>
            <p className="font-futuristic text-xs tracking-[0.2em] text-cyan-200">INITIALIZE CONNECTION</p>
            <p className="text-sm font-light">Awaiting neural input to begin communication.</p>
          </div>
        )}

        {messages.map((msg) => (
          <div 
            key={msg.id}
            className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-in fade-in slide-in-from-bottom-2 duration-500`}
          >
            <div className={`max-w-[85%] relative ${msg.role === 'user' ? 'text-right' : 'text-left'}`}>
              <div className={`
                px-4 py-3 rounded-2xl text-sm leading-relaxed relative
                ${msg.role === 'user' 
                  ? 'bg-gradient-to-br from-cyan-900/40 to-cyan-600/40 border border-cyan-400/30 text-cyan-50 glow-blue' 
                  : 'glass-panel text-gray-100 border-white/10 glow-purple'}
              `}>
                {msg.content}

                {/* Visual Accent for bot */}
                {msg.role === 'assistant' && (
                   <div className="absolute -left-1 top-0 bottom-0 w-0.5 bg-gradient-to-b from-purple-500 to-transparent"></div>
                )}
              </div>
              <span className="text-[10px] opacity-30 mt-1 block px-2 font-futuristic">
                {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
              </span>
            </div>
          </div>
        ))}

        {status === AppStatus.THINKING && (
          <div className="flex justify-start animate-pulse">
            <div className="glass-panel px-4 py-3 rounded-2xl border-white/10 flex items-center space-x-2">
              <div className="w-1 h-1 bg-purple-400 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
              <div className="w-1 h-1 bg-purple-400 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
              <div className="w-1 h-1 bg-purple-400 rounded-full animate-bounce"></div>
            </div>
          </div>
        )}
      </main>

      {/* Controls */}
      <footer className="relative z-10 p-4 pb-8 glass-panel border-t border-white/5 space-y-4">
        {/* Status Indicator */}
        <div className="flex items-center justify-between text-[10px] font-futuristic tracking-widest px-2">
          <div className="flex items-center gap-2">
            <div className={`w-1.5 h-1.5 rounded-full ${status === AppStatus.LISTENING ? 'bg-red-500 animate-ping' : 'bg-cyan-500'}`}></div>
            <span className={status === AppStatus.LISTENING ? 'text-red-400' : 'text-cyan-400 opacity-60'}>
              {status}
            </span>
          </div>
          <button 
            onClick={() => setIsMuted(!isMuted)}
            className={`transition-colors ${isMuted ? 'text-red-400' : 'text-cyan-400 opacity-60 hover:opacity-100'}`}
          >
            {isMuted ? 'AUDIO: OFF' : 'AUDIO: ON'}
          </button>
        </div>

        <div className="flex items-center gap-3">
          {/* Microphone */}
          <button
            onClick={toggleVoiceInput}
            className={`
              shrink-0 w-12 h-12 rounded-full flex items-center justify-center transition-all duration-300
              ${status === AppStatus.LISTENING 
                ? 'bg-red-500/20 border-2 border-red-500 shadow-[0_0_15px_rgba(239,68,68,0.5)]' 
                : 'bg-cyan-500/10 border border-cyan-500/40 hover:bg-cyan-500/20'}
            `}
          >
            <svg 
              className={`w-5 h-5 ${status === AppStatus.LISTENING ? 'text-red-400' : 'text-cyan-400'} ${status === AppStatus.SPEAKING ? 'animate-pulse' : ''}`} 
              fill="none" viewBox="0 0 24 24" stroke="currentColor"
            >
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
            </svg>
          </button>

          {/* Text Input */}
          <div className="flex-1 relative group">
            <input
              type="text"
              value={inputValue}
              onChange={(e) => setInputValue(e.target.value)}
              onKeyPress={(e) => e.key === 'Enter' && handleSendMessage()}
              placeholder="Neural transmission..."
              className="w-full bg-white/5 border border-white/10 rounded-2xl py-3 px-4 focus:outline-none focus:border-cyan-500/50 focus:bg-white/10 transition-all duration-300 text-sm placeholder:text-gray-600"
            />
            {status === AppStatus.SPEAKING && (
              <div className="absolute right-3 top-1/2 -translate-y-1/2 flex gap-0.5 items-end h-4">
                <div className="w-0.5 bg-cyan-400 animate-[bounce_0.5s_infinite]"></div>
                <div className="w-0.5 bg-cyan-400 animate-[bounce_0.7s_infinite_0.1s]"></div>
                <div className="w-0.5 bg-cyan-400 animate-[bounce_0.6s_infinite_0.2s]"></div>
              </div>
            )}
          </div>

          {/* Send Button */}
          <button
            onClick={() => handleSendMessage()}
            disabled={!inputValue.trim()}
            className="shrink-0 w-12 h-12 bg-gradient-to-br from-purple-600 to-blue-600 rounded-2xl flex items-center justify-center shadow-lg shadow-purple-500/20 hover:scale-105 active:scale-95 transition-all disabled:opacity-30 disabled:grayscale"
          >
            <svg className="w-5 h-5 text-white transform rotate-45 -translate-y-0.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" />
            </svg>
          </button>
        </div>
      </footer>
    </div>
  );
};

export default App;

export interface Message {
  id: string;
  role: 'user' | 'assistant';
  content: string;
  timestamp: number;
  translation?: string;
  lang?: string;
}

export enum AppStatus {
  IDLE = 'IDLE',
  LISTENING = 'LISTENING',
  THINKING = 'THINKING',
  SPEAKING = 'SPEAKING',
  TRANSLATING = 'TRANSLATING'
}

export interface UserProfile {
  name: string;
  city: string;
  institution: string;
  profilePic: string;
  idNumber: string;
}

export const SUPPORTED_LANGUAGES = [
  { code: 'Urdu', name: 'Urdu' },
  { code: 'Hindi', name: 'Hindi' },
  { code: 'Punjabi', name: 'Punjabi' },
  { code: 'Pashto', name: 'Pashto' },
  { code: 'Chinese', name: 'Chinese' }
];

import { GoogleGenAI, GenerateContentResponse, Modality } from "@google/genai";

const API_KEY = process.env.API_KEY || "";

export const getGeminiChatResponse = async (prompt: string, history: {role: string, content: string}[]) => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });

  const contents = [
    ...history.map(h => ({
      role: h.role === 'user' ? 'user' : 'model',
      parts: [{ text: h.content }]
    })),
    { role: 'user', parts: [{ text: prompt }] }
  ];

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: contents as any,
      config: {
        systemInstruction: "You are GCT.ET, a highly intelligent, futuristic AI assistant. Your goal is to provide deep, accurate, and helpful answers. Your tone is sleek, efficient, and professional. Always prioritize correctness.",
        temperature: 0.7,
      }
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Chat Error:", error);
    return "The neural link is unstable. Please try again.";
  }
};

export const translateText = async (text: string, targetLanguage: string) => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [{ role: 'user', parts: [{ text: `Translate the following text into ${targetLanguage}. Return ONLY the translated text: ${text}` }] }],
    });
    return response.text;
  } catch (error) {
    console.error("Translation Error:", error);
    return null;
  }
};

export const generateSpeech = async (text: string): Promise<string | undefined> => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Kore' },
          },
        },
      },
    });

    return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  } catch (error) {
    console.error("Gemini TTS Error:", error);
    return undefined;
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { Message, AppStatus, UserProfile, SUPPORTED_LANGUAGES } from './types';
import Logo from './components/Logo';
import { getGeminiChatResponse, generateSpeech, translateText } from './services/geminiService';

const App: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [showProfileModal, setShowProfileModal] = useState(false);
  const [tempProfile, setTempProfile] = useState<Partial<UserProfile>>({
    name: '', city: '', institution: '', profilePic: '', idNumber: 'GCT-' + Math.floor(1000 + Math.random() * 9000)
  });

  const scrollRef = useRef<HTMLDivElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const [recognition, setRecognition] = useState<any>(null);

  useEffect(() => {
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
      const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
      const recog = new SpeechRecognition();
      recog.continuous = false;
      recog.lang = 'en-US';
      recog.onstart = () => setStatus(AppStatus.LISTENING);
      recog.onresult = (event: any) => handleSendMessage(event.results[0][0].transcript);
      recog.onerror = () => setStatus(AppStatus.IDLE);
      recog.onend = () => setStatus(AppStatus.IDLE);
      setRecognition(recog);
    }
  }, []);

  const scrollToBottom = () => scrollRef.current?.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
  useEffect(scrollToBottom, [messages, status]);

  const decodeAndPlay = async (base64: string) => {
    if (!audioContextRef.current) audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    const ctx = audioContextRef.current;
    const binaryString = atob(base64);
    const bytes = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) bytes[i] = binaryString.charCodeAt(i);
    const dataInt16 = new Int16Array(bytes.buffer);
    const buffer = ctx.createBuffer(1, dataInt16.length, 24000);
    const channelData = buffer.getChannelData(0);
    for (let i = 0; i < dataInt16.length; i++) channelData[i] = dataInt16[i] / 32768.0;
    const source = ctx.createBufferSource();
    source.buffer = buffer;
    source.connect(ctx.destination);
    source.start();
    return source;
  };

  const handleSendMessage = async (text: string = inputValue) => {
    if (!text.trim()) return;
    const userMsg: Message = { id: Date.now().toString(), role: 'user', content: text, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    setInputValue('');
    setStatus(AppStatus.THINKING);

    const history = messages.slice(-6).map(m => ({ role: m.role, content: m.content }));
    const responseText = await getGeminiChatResponse(text, history);
    const botMsg: Message = { id: (Date.now() + 1).toString(), role: 'assistant', content: responseText || "Neural failure.", timestamp: Date.now() };
    setMessages(prev => [...prev, botMsg]);
    setStatus(AppStatus.IDLE);
  };

  const handleTranslate = async (msgId: string, lang: string) => {
    const msg = messages.find(m => m.id === msgId);
    if (!msg) return;
    setStatus(AppStatus.TRANSLATING);
    const translated = await translateText(msg.content, lang);
    if (translated) {
      setMessages(prev => prev.map(m => m.id === msgId ? { ...m, translation: translated, lang } : m));
    }
    setStatus(AppStatus.IDLE);
  };

  const handleListen = async (text: string) => {
    setStatus(AppStatus.SPEAKING);
    const audio = await generateSpeech(text);
    if (audio) {
      const source = await decodeAndPlay(audio);
      source.onended = () => setStatus(AppStatus.IDLE);
    } else setStatus(AppStatus.IDLE);
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setTempProfile(prev => ({ ...prev, profilePic: reader.result as string }));
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className="flex flex-col h-screen max-w-md mx-auto relative bg-[#050505] shadow-2xl overflow-hidden border-x border-white/10">
      {/* HUD Header */}
      <header className="relative z-20 px-4 pt-2 flex items-center justify-between border-b border-white/5 bg-black/40 backdrop-blur-md">
        <Logo />
        <button 
          onClick={() => setShowProfileModal(true)}
          className="p-2 rounded-full border border-cyan-500/30 text-cyan-400 hover:bg-cyan-500/10 transition-all flex items-center gap-2 group"
        >
          {profile?.profilePic ? (
            <img src={profile.profilePic} className="w-8 h-8 rounded-full border border-cyan-400" alt="ID" />
          ) : (
            <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M5.121 17.804A13.937 13.937 0 0112 16c2.5 0 4.847.655 6.879 1.804M15 10a3 3 0 11-6 0 3 3 0 016 0zm6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
          )}
          <span className="text-[10px] font-futuristic hidden group-hover:inline uppercase tracking-widest">ID Card</span>
        </button>
      </header>

      {/* Main Chat Display */}
      <main ref={scrollRef} className="flex-1 overflow-y-auto px-4 py-6 space-y-8 z-10 scroll-smooth">
        {messages.length === 0 && (
