import { GoogleGenAI, GenerateContentResponse, Modality } from "@google/genai";
import { Attachment } from "../types";

const API_KEY = process.env.API_KEY || "";

export const getGeminiChatResponse = async (
  prompt: string, 
  history: {role: string, content: string}[],
  attachments: Attachment[] = []
) => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });

  const historyParts = history.map(h => ({
    role: h.role === 'user' ? 'user' : 'model',
    parts: [{ text: h.content }]
  }));

  const currentParts: any[] = [{ text: prompt }];

  attachments.forEach(att => {
    currentParts.push({
      inlineData: {
        data: att.data.split(',')[1], // Strip data:mime;base64,
        mimeType: att.mimeType
      }
    });
  });

  const contents = [
    ...historyParts,
    { role: 'user', parts: currentParts }
  ];

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview', // Fastest model
      contents: contents as any,
      config: {
        systemInstruction: `You are GCT.ET, a high-speed AI specialist in Electrical Technology. 
        Provide clear, structured, and technically accurate answers like Gemini or ChatGPT. 
        Use bullet points for lists. Format your output cleanly. 
        If you see an image or file, analyze it with precision.`,
        temperature: 0.4, // Lower temperature for more consistent technical answers
      }
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Chat Error:", error);
    return "Neural transmission failed. System error.";
  }
};

export const translateText = async (text: string, targetLanguage: string) => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [{ role: 'user', parts: [{ text: `Translate precisely to ${targetLanguage}: ${text}` }] }],
    });
    return response.text;
  } catch (error) {
    return null;
  }
};

export const generateSpeech = async (text: string): Promise<string | undefined> => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Kore' },
          },
        },
      },
    });
    return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  } catch (error) {
    return undefined;
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { Message, AppStatus, UserProfile, SUPPORTED_LANGUAGES, ELECTRICAL_TEMPLATES, Theme, Attachment } from './types';
import Logo from './components/Logo';
import { getGeminiChatResponse, generateSpeech, translateText } from './services/geminiService';

const App: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [theme, setTheme] = useState<Theme>('dark');
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [showProfileModal, setShowProfileModal] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [pendingAttachments, setPendingAttachments] = useState<Attachment[]>([]);

  const [tempProfile, setTempProfile] = useState<Partial<UserProfile>>({
    name: '', city: '', institution: '', profilePic: '', idNumber: 'GCT-' + Math.floor(1000 + Math.random() * 9000)
  });

  const scrollRef = useRef<HTMLDivElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const [isCameraActive, setIsCameraActive] = useState(false);
  const [recognition, setRecognition] = useState<any>(null);

  useEffect(() => {
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
      const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
      const recog = new SpeechRecognition();
      recog.continuous = false;
      recog.onstart = () => setStatus(AppStatus.LISTENING);
      recog.onresult = (event: any) => handleSendMessage(event.results[0][0].transcript);
      recog.onerror = () => setStatus(AppStatus.IDLE);
      recog.onend = () => setStatus(AppStatus.IDLE);
      setRecognition(recog);
    }
  }, []);

  const scrollToBottom = () => scrollRef.current?.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
  useEffect(scrollToBottom, [messages, status]);

  const handleSendMessage = async (text: string = inputValue) => {
    if (!text.trim() && pendingAttachments.length === 0) return;

    const currentAttachments = [...pendingAttachments];
    const userMsg: Message = { 
      id: Date.now().toString(), 
      role: 'user', 
      content: text, 
      timestamp: Date.now(),
      attachments: currentAttachments
    };

    setMessages(prev => [...prev, userMsg]);
    setInputValue('');
    setPendingAttachments([]);
    setStatus(AppStatus.THINKING);

    const history = messages.slice(-10).map(m => ({ role: m.role, content: m.content }));
    const responseText = await getGeminiChatResponse(text || "Please analyze the attached content.", history, currentAttachments);

    const botMsg: Message = { 
      id: (Date.now() + 1).toString(), 
      role: 'assistant', 
      content: responseText || "Neural failure. Please retry.", 
      timestamp: Date.now() 
    };
    setMessages(prev => [...prev, botMsg]);
    setStatus(AppStatus.IDLE);
  };

  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        setIsCameraActive(true);
      }
    } catch (err) {
      alert("Camera access denied.");
    }
  };

  const capturePhoto = () => {
    if (videoRef.current) {
      const canvas = document.createElement('canvas');
      canvas.width = videoRef.current.videoWidth;
      canvas.height = videoRef.current.videoHeight;
      const ctx = canvas.getContext('2d');
      ctx?.drawImage(videoRef.current, 0, 0);
      const data = canvas.toDataURL('image/jpeg');
      setPendingAttachments(prev => [...prev, { data, mimeType: 'image/jpeg' }]);
      stopCamera();
    }
  };

  const stopCamera = () => {
    if (videoRef.current && videoRef.current.srcObject) {
      (videoRef.current.srcObject as MediaStream).getTracks().forEach(track => track.stop());
      setIsCameraActive(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setPendingAttachments(prev => [...prev, { data: reader.result as string, mimeType: file.type }]);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleListen = async (text: string) => {
    setStatus(AppStatus.SPEAKING);
    const audio = await generateSpeech(text);
    if (audio) {
      const ctx = audioContextRef.current || (audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 }));
      const binary = atob(audio);
      const bytes = new Uint8Array(binary.length);
      for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
      const dataInt16 = new Int16Array(bytes.buffer);
      const buffer = ctx.createBuffer(1, dataInt16.length, 24000);
      buffer.getChannelData(0).set(Array.from(dataInt16).map(v => v / 32768.0));
      const source = ctx.createBufferSource();
      source.buffer = buffer;
      source.connect(ctx.destination);
      source.onended = () => setStatus(AppStatus.IDLE);
      source.start();
    } else setStatus(AppStatus.IDLE);
  };

  return (
    <div className={`flex flex-col h-screen max-w-md mx-auto relative overflow-hidden transition-colors duration-500 ${theme === 'dark' ? 'bg-[#050505] text-white' : 'bg-[#f4f7f6] text-gray-800'}`}>

      {/* Animated Background */}
      <div className="absolute inset-0 z-0 pointer-events-none overflow-hidden">
        <div className={`absolute -inset-[100%] animate-[spin_20s_linear_infinite] opacity-30 ${theme === 'dark' ? 'bg-[conic-gradient(from_0deg,#00ffa3,#0077ff,#bc13fe,#00ffa3)]' : 'bg-[conic-gradient(from_0deg,#3b82f6,#8b5cf6,#3b82f6)]'} blur-[150px]`}></div>
        <div className={`absolute inset-0 ${theme === 'dark' ? 'bg-[#050505]/80' : 'bg-white/70'} backdrop-blur-3xl`}></div>
      </div>

      {/* Header */}
      <header className={`relative z-20 px-4 py-2 flex items-center justify-between border-b backdrop-blur-xl ${theme === 'dark' ? 'border-white/10 bg-black/40' : 'border-gray-200 bg-white/40'}`}>
        <Logo />
        <div className="flex items-center gap-2">
           <button onClick={() => setShowSettings(!showSettings)} className="p-2 rounded-full hover:bg-white/10 transition-all">
             <svg className="w-5 h-5 opacity-60" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" strokeWidth={2}/><circle cx="12" cy="12" r="3" strokeWidth={2}/></svg>
           </button>
           <button onClick={() => setShowProfileModal(true)} className={`p-1.5 rounded-full border transition-all ${theme === 'dark' ? 'border-cyan-500/30' : 'border-blue-500/30'}`}>
            {profile?.profilePic ? <img src={profile.profilePic} className="w-7 h-7 rounded-full" /> : <svg className="w-5 h-5 text-cyan-500" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" /></svg>}
           </button>
        </div>
      </header>

      {/* Main Area */}
      <main ref={scrollRef} className="flex-1 overflow-y-auto z-10 p-4 space-y-6 scroll-smooth">
        {messages.length === 0 && (
          <div className="py-10 space-y-6">
            <div className="text-center space-y-2">
              <h2 className={`font-futuristic text-xl tracking-tighter ${theme === 'dark' ? 'text-cyan-400' : 'text-blue-600'}`}>GCT NEURAL CORE</h2>
              <p className="text-xs opacity-50 uppercase tracking-[0.4em]">Ready for Electrical Analysis</p>
            </div>

            <div className="grid grid-cols-1 gap-2">
              {ELECTRICAL_TEMPLATES.map((t, idx) => (
                <button key={idx} onClick={() => handleSendMessage(t)} className={`text-left p-3 rounded-xl border text-xs transition-all ${theme === 'dark' ? 'bg-white/5 border-white/10 hover:bg-white/10 hover:border-cyan-500/50' : 'bg-white border-gray-200 hover:border-blue-500'}`}>
                  {t}
                </button>
              ))}
            </div>
          </div>
        )}

        {messages.map((msg) => (
          <div key={msg.id} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'} animate-in fade-in slide-in-from-bottom-2`}>
            <div className={`max-w-[90%] p-4 rounded-2xl shadow-sm ${msg.role === 'user' ? (theme === 'dark' ? 'bg-cyan-900/40 border border-cyan-500/30' : 'bg-blue-600 text-white') : (theme === 'dark' ? 'bg-white/5 border border-white/10' : 'bg-white border-gray-200')}`}>
              {msg.attachments?.map((att, i) => (
                <img key={i} src={att.data} className="w-full h-32 object-cover rounded-lg mb-2 border border-white/10" />
              ))}
              <div className={`whitespace-pre-wrap text-sm leading-relaxed ${msg.role === 'assistant' ? 'font-light' : ''}`}>
                {msg.translation || msg.content}
              </div>
              {msg.role === 'assistant' && (
                <div className="mt-3 flex items-center gap-4 opacity-70 border-t border-white/5 pt-2">
                  <button onClick={() => handleListen(msg.translation || msg.content)} className="flex items-center gap-1 text-[10px] uppercase font-futuristic hover:opacity-100">
                    <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M15.536 8.464a5 5 0 010 7.072M18.364 5.636a9 9 0 010 12.728M12 9v6m-4-3h1" strokeWidth={2}/></svg>
                    Listen
                  </button>
                  <div className="relative group">
                    <button className="flex items-center gap-1 text-[10px] uppercase font-futuristic hover:opacity-100">
                      Translate
                    </button>
                    <div className="absolute bottom-full left-0 mb-2 hidden group-hover:flex flex-col bg-black/90 border border-white/20 rounded-lg overflow-hidden z-50">
                      {SUPPORTED_LANGUAGES.map(l => (
                        <button key={l.code} onClick={() => translateText(msg.content, l.code).then(t => t && setMessages(prev => prev.map(m => m.id === msg.id ? {...m, translation: t, lang: l.name} : m)))} className="px-3 py-1.5 text-[10px] hover:bg-white/10 text-white text-left">{l.name}</button>
                      ))}
                    </div>
                  </div>
                </div>
              )}
            </div>
            <span className="text-[8px] opacity-30 mt-1 uppercase tracking-widest">{new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
          </div>
        ))}
      </main>

      {/* Input Module */}
      <footer className={`relative z-20 p-4 border-t backdrop-blur-3xl ${theme === 'dark' ? 'bg-black/60 border-white/10' : 'bg-white/80 border-gray-200'}`}>
        {pendingAttachments.length > 0 && (
          <div className="flex gap-2 mb-3 overflow-x-auto pb-2">
            {pendingAttachments.map((att, i) => (
              <div key={i} className="relative shrink-0">
                <img src={att.data} className="w-12 h-12 rounded-lg object-cover border border-white/20" />
                <button onClick={() => setPendingAttachments(p => p.filter((_, j) => i !== j))} className="absolute -top-1 -right-1 bg-red-500 rounded-full p-0.5"><svg className="w-3 h-3 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M6 18L18 6M6 6l12 12" strokeWidth={3}/></svg></button>
              </div>
            ))}
          </div>
        )}

        <div className="flex items-center gap-2">
          <div className="flex gap-1">
            <button onClick={() => fileInputRef.current?.click()} className={`p-2.5 rounded-xl transition-all ${theme === 'dark' ? 'bg-white/5 hover:bg-white/10' : 'bg-gray-100 hover:bg-gray-200'}`}>
              <svg className="w-5 h-5 opacity-60" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M15.172 7l-6.586 6.586a2 2 0 102.828 2.828l6.414-6.586a4 4 0 00-5.656-5.656l-6.415 6.585a6 6 0 108.486 8.486L20.5 13" strokeWidth={2}/></svg>
              <input type="file" ref={fileInputRef} onChange={handleFileUpload} hidden />
            </button>
            <button onClick={startCamera} className={`p-2.5 rounded-xl transition-all ${theme === 'dark' ? 'bg-white/5 hover:bg-white/10' : 'bg-gray-100 hover:bg-gray-200'}`}>
              <svg className="w-5 h-5 opacity-60" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" strokeWidth={2}/><circle cx="12" cy="13" r="3" strokeWidth={2}/></svg>
            </button>
          </div>

          <div className="flex-1 relative">
            <input 
              value={inputValue} 
              onChange={e => setInputValue(e.target.value)}
              onKeyDown={e => e.key === 'Enter' && handleSendMessage()}
              placeholder="Transmission command..."
              className={`w-full py-3 px-4 rounded-2xl text-sm transition-all focus:ring-1 focus:outline-none ${theme === 'dark' ? 'bg-white/5 border-white/10 text-white focus:ring-cyan-500/50' : 'bg-gray-100 border-gray-200 focus:ring-blue-500'}`}
            />
          </div>

          <button 
            onClick={() => handleSendMessage()}
            className={`w-12 h-12 flex items-center justify-center rounded-2xl transition-all shadow-lg ${theme === 'dark' ? 'bg-cyan-600 hover:bg-cyan-500' : 'bg-blue-600 hover:bg-blue-500'} disabled:opacity-30`}
          >
            <svg className="w-5 h-5 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" strokeWidth={2.5}/></svg>
          </button>
        </div>
      </footer>

      {/* Camera Overlay */}
      {isCameraActive && (
        <div className="absolute inset-0 z-[100] bg-black flex flex-col items-center justify-center">
          <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover" />
          <div className="absolute bottom-10 flex gap-10">
            <button onClick={stopCamera} className="w-16 h-16 bg-white/10 rounded-full flex items-center justify-center border border-white/20"><svg className="w-8 h-8 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M6 18L18 6M6 6l12 12" strokeWidth={2}/></svg></button>
            <button onClick={capturePhoto} className="w-20 h-20 bg-white rounded-full border-4 border-white/30 flex items-center justify-center shadow-2xl"></button>
          </div>
        </div>
      )}

      {/* Settings Modal */}
      {showSettings && (
        <div className="absolute inset-0 z-50 flex items-end animate-in slide-in-from-bottom-full duration-300">
          <div className="w-full h-2/3 bg-black/80 backdrop-blur-3xl rounded-t-[3rem] p-8 border-t border-white/10 shadow-2xl">
            <div className="flex justify-between items-center mb-10">
              <h3 className="font-futuristic text-cyan-400 tracking-[0.3em]">CORE SETTINGS</h3>
              <button onClick={() => setShowSettings(false)} className="opacity-50 hover:opacity-100"><svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M6 18L18 6M6 6l12 12" /></svg></button>
            </div>
            <div className="space-y-6">
              <div className="flex justify-between items-center p-4 bg-white/5 rounded-2xl border border-white/5">
                <span className="text-sm font-futuristic uppercase tracking-widest opacity-60">System Theme</span>
                <div className="flex bg-black p-1 rounded-xl">
                  <button onClick={() => setTheme('dark')} className={`px-4 py-2 rounded-lg text-[10px] font-futuristic transition-all ${theme === 'dark' ? 'bg-cyan-500 text-black' : 'opacity-40'}`}>DARK</button>
                  <button onClick={() => setTheme('light')} className={`px-4 py-2 rounded-lg text-[10px] font-futuristic transition-all ${theme === 'light' ? 'bg-blue-500 text-white' : 'opacity-40'}`}>LIGHT</button>
                </div>
              </div>
              <p className="text-[9px] text-center opacity-30 font-futuristic tracking-[0.5em] mt-10">GCT.ET NEURAL VERSION 4.2.0</p>
            </div>
          </div>
        </div>
      )}

      {/* Profile/ID Modal Logic (Keep existing ID Modal from previous version but adapt styles) */}
      {showProfileModal && (
        <div className="absolute inset-0 z-[100] flex items-center justify-center p-4 bg-black/95 backdrop-blur-md animate-in fade-in">
          <div className="w-full max-w-xs space-y-6">
            {!profile ? (
              <div className="bg-white/5 p-6 rounded-[2.5rem] border border-white/10 space-y-4 shadow-2xl">
                <h2 className="font-futuristic text-center text-cyan-400 text-xs tracking-widest">NEURAL IDENTITY CREATION</h2>
                <div className="space-y-2">
                  <input placeholder="NEURAL NAME" className="w-full bg-white/5 border border-white/10 p-4 rounded-2xl text-[10px] font-futuristic" onChange={e => setTempProfile(p => ({...p, name: e.target.value}))} />
                  <input placeholder="ACADEMY/UNIVERSITY" className="w-full bg-white/5 border border-white/10 p-4 rounded-2xl text-[10px] font-futuristic" onChange={e => setTempProfile(p => ({...p, institution: e.target.value}))} />
                  <button onClick={() => {if(tempProfile.name) setProfile(tempProfile as UserProfile)}} className="w-full bg-cyan-600 p-4 rounded-2xl font-futuristic text-xs tracking-[0.3em] shadow-lg shadow-cyan-500/20">INITIATE ID</button>
                </div>
                <button onClick={() => setShowProfileModal(false)} className="w-full text-[9px] opacity-30 hover:opacity-100 font-futuristic text-center">CANCEL SCAN</button>
              </div>
            ) : (
              <div id="id-card-capture" className="relative group perspective-1000 animate-in zoom-in-95 duration-500">
                <div className="w-full aspect-[1.6/1] bg-gradient-to-br from-gray-900 to-black rounded-[2rem] border border-cyan-500/30 p-5 shadow-[0_0_50px_rgba(6,182,212,0.2)] overflow-hidden flex flex-col justify-between">
                   <div className="flex justify-between items-start">
                     <div className="flex gap-4">
                       <div className="w-14 h-14 rounded-xl border border-cyan-500/50 overflow-hidden bg-black/50">
                         {profile.profilePic ? <img src={profile.profilePic} className="w-full h-full object-cover" /> : <div className="w-full h-full flex items-center justify-center opacity-20"><svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20"><path d="M10 9a3 3 0 100-6 3 3 0 000 6zm-7 9a7 7 0 1114 0H3z" /></svg></div>}
                       </div>
                       <div>
                         <h3 className="font-futuristic text-white text-[10px] tracking-widest">{profile.name}</h3>
                         <p className="text-[7px] text-cyan-400 opacity-60 uppercase font-futuristic mt-0.5">{profile.institution}</p>
                         <p className="text-[7px] text-white/40 font-futuristic mt-3">ID: {profile.idNumber}</p>
                       </div>
                     </div>
                     <Logo />
                   </div>
                   <div className="flex justify-between items-end border-t border-white/5 pt-3">
                     <p className="text-[6px] font-futuristic tracking-[0.4em] opacity-40 uppercase">Electrical Sector Division</p>
                     <div className="flex gap-0.5">
                       {[1,2,3,4].map(i => <div key={i} className="w-1 h-3 bg-cyan-500/20 rounded-full"></div>)}
                     </div>
                   </div>
                   <div className="absolute inset-0 pointer-events-none bg-gradient-to-b from-transparent via-cyan-500/10 to-transparent h-1 w-full animate-[idscan_4s_linear_infinite]"></div>
                </div>
                <div className="flex gap-2 mt-6">
                  <button onClick={() => window.print()} className="flex-1 bg-cyan-600/20 border border-cyan-500/40 p-3 rounded-2xl font-futuristic text-[9px] tracking-widest hover:bg-cyan-500/40">EXPORT DATA</button>
                  <button onClick={() => setProfile(null)} className="flex-1 bg-white/5 border border-white/10 p-3 rounded-2xl font-futuristic text-[9px] tracking-widest">REINITIALIZE</button>
                </div>
                <button onClick={() => setShowProfileModal(false)} className="w-full text-[9px] opacity-30 hover:opacity-100 font-futuristic text-center mt-6">CLOSE PROFILE</button>
              </div>
            )}
          </div>
        </div>
      )}

      {/* Global Status Bar */}
      {status === AppStatus.THINKING && (
        <div className="absolute top-16 left-1/2 -translate-x-1/2 z-[100] bg-cyan-500/10 border border-cyan-500/40 px-6 py-1 rounded-full backdrop-blur-2xl shadow-2xl animate-pulse">
           <span className="text-[9px] font-futuristic tracking-[0.5em] text-cyan-400">ANALYZING...</span>
        </div>
      )}

      <style>{`
        @keyframes idscan {
          0% { transform: translateY(-100%); }
          100% { transform: translateY(500%); }
        }
        @media print {
          body * { visibility: hidden; }
          #id-card-capture, #id-card-capture * { visibility: visible; }
          #id-card-capture { position: fixed; left: 50%; top: 50%; transform: translate(-50%, -50%) scale(2); }
        }
      `}</style>
    </div>
  );
};

