import React, { useState, useRef, useEffect } from 'react';
import { Message, AppStatus, UserProfile, SUPPORTED_LANGUAGES, ELECTRICAL_TEMPLATES, Theme, Attachment } from './types';
import Logo from './components/Logo';
import { getGeminiChatResponse, generateSpeech, translateText } from './services/geminiService';

const App: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [theme, setTheme] = useState<Theme>('dark');
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [showProfileModal, setShowProfileModal] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [pendingAttachments, setPendingAttachments] = useState<Attachment[]>([]);

  const [tempProfile, setTempProfile] = useState<Partial<UserProfile>>({
    name: '', city: '', institution: '', profilePic: '', idNumber: 'GCT-' + Math.floor(1000 + Math.random() * 9000)
  });

  const scrollRef = useRef<HTMLDivElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const [isCameraActive, setIsCameraActive] = useState(false);
  const [recognition, setRecognition] = useState<any>(null);

  useEffect(() => {
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
      const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
      const recog = new SpeechRecognition();
      recog.continuous = false;
      recog.onstart = () => setStatus(AppStatus.LISTENING);
      recog.onresult = (event: any) => handleSendMessage(event.results[0][0].transcript);
      recog.onerror = () => setStatus(AppStatus.IDLE);
      recog.onend = () => setStatus(AppStatus.IDLE);
      setRecognition(recog);
    }
  }, []);

  const scrollToBottom = () => scrollRef.current?.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
  useEffect(scrollToBottom, [messages, status]);

  const handleSendMessage = async (text: string = inputValue) => {
    if (!text.trim() && pendingAttachments.length === 0) return;

    const currentAttachments = [...pendingAttachments];
    const userMsg: Message = { 
      id: Date.now().toString(), 
      role: 'user', 
      content: text, 
      timestamp: Date.now(),
      attachments: currentAttachments
    };

    setMessages(prev => [...prev, userMsg]);
    setInputValue('');
    setPendingAttachments([]);
    setStatus(AppStatus.THINKING);

    const history = messages.slice(-10).map(m => ({ role: m.role, content: m.content }));
    const responseText = await getGeminiChatResponse(text || "Analyzing provided electrical diagnostic data.", history, currentAttachments);

    const botMsg: Message = { 
      id: (Date.now() + 1).toString(), 
      role: 'assistant', 
      content: responseText || "Neural interface failure. Please re-establish connection.", 
      timestamp: Date.now() 
    };
    setMessages(prev => [...prev, botMsg]);
    setStatus(AppStatus.IDLE);
  };

  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        setIsCameraActive(true);
      }
    } catch (err) {
      alert("Camera access restricted.");
    }
  };

  const capturePhoto = () => {
    if (videoRef.current) {
      const canvas = document.createElement('canvas');
      canvas.width = videoRef.current.videoWidth;
      canvas.height = videoRef.current.videoHeight;
      const ctx = canvas.getContext('2d');
      ctx?.drawImage(videoRef.current, 0, 0);
      const data = canvas.toDataURL('image/jpeg');
      setPendingAttachments(prev => [...prev, { data, mimeType: 'image/jpeg' }]);
      stopCamera();
    }
  };

  const stopCamera = () => {
    if (videoRef.current && videoRef.current.srcObject) {
      (videoRef.current.srcObject as MediaStream).getTracks().forEach(track => track.stop());
      setIsCameraActive(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setPendingAttachments(prev => [...prev, { data: reader.result as string, mimeType: file.type }]);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleListen = async (text: string) => {
    setStatus(AppStatus.SPEAKING);
    const audio = await generateSpeech(text);
    if (audio) {
      const ctx = audioContextRef.current || (audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 }));
      const binary = atob(audio);
      const bytes = new Uint8Array(binary.length);
      for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
      const dataInt16 = new Int16Array(bytes.buffer);
      const buffer = ctx.createBuffer(1, dataInt16.length, 24000);
      buffer.getChannelData(0).set(Array.from(dataInt16).map(v => v / 32768.0));
      const source = ctx.createBufferSource();
      source.buffer = buffer;
      source.connect(ctx.destination);
      source.onended = () => setStatus(AppStatus.IDLE);
      source.start();
    } else setStatus(AppStatus.IDLE);
  };

  return (
    <div className={`flex flex-col h-screen max-w-md mx-auto relative overflow-hidden transition-all duration-700 ${theme === 'dark' ? 'bg-[#050505] text-[#e2e8f0]' : 'bg-[#f8fafc] text-[#1e293b]'}`}>

      {/* Dynamic Energy Background */}
      <div className="absolute inset-0 z-0 pointer-events-none overflow-hidden">
        <div className={`absolute -inset-[100%] animate-[spin_30s_linear_infinite] opacity-20 ${theme === 'dark' ? 'bg-[conic-gradient(from_0deg,#fbbf24,#0891b2,#fbbf24)]' : 'bg-[conic-gradient(from_0deg,#3b82f6,#fbbf24,#3b82f6)]'} blur-[160px]`}></div>
        <div className={`absolute inset-0 ${theme === 'dark' ? 'bg-[#050505]/85' : 'bg-white/75'} backdrop-blur-3xl`}></div>
        {/* Animated Particles (Simplified) */}
        <div className="absolute top-10 left-10 w-1 h-1 bg-amber-400 rounded-full animate-pulse shadow-[0_0_10px_#fbbf24]"></div>
        <div className="absolute bottom-40 right-20 w-1 h-1 bg-cyan-400 rounded-full animate-pulse shadow-[0_0_10px_#22d3ee]"></div>
      </div>

      {/* Header */}
      <header className={`relative z-20 px-4 py-2 flex items-center justify-between border-b backdrop-blur-2xl ${theme === 'dark' ? 'border-white/10 bg-black/50' : 'border-gray-200 bg-white/50'}`}>
        <Logo />
        <div className="flex items-center gap-3">
           <button onClick={() => setShowSettings(!showSettings)} className="p-2 rounded-full hover:bg-white/10 transition-all text-amber-500">
             <svg className="w-5 h-5 opacity-80" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" strokeWidth={2}/><circle cx="12" cy="12" r="3" strokeWidth={2}/></svg>
           </button>
           <button onClick={() => setShowProfileModal(true)} className={`p-1.5 rounded-xl border transition-all ${theme === 'dark' ? 'border-amber-500/40 bg-amber-500/5' : 'border-blue-500/40 bg-blue-500/5'}`}>
            {profile?.profilePic ? <img src={profile.profilePic} className="w-7 h-7 rounded-lg" /> : <svg className="w-5 h-5 text-amber-500" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" /></svg>}
           </button>
        </div>
      </header>

      {/* Main Area */}
      <main ref={scrollRef} className="flex-1 overflow-y-auto z-10 p-5 space-y-8 scroll-smooth pb-20">
        {messages.length === 0 && (
          <div className="py-12 space-y-8 animate-in fade-in zoom-in duration-1000">
