import { GoogleGenAI, GenerateContentResponse, Modality } from "@google/genai";
import { Attachment } from "../types";

const API_KEY = process.env.API_KEY || "";

export const getGeminiChatResponse = async (
  prompt: string, 
  history: {role: string, content: string}[],
  attachments: Attachment[] = []
) => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });

  const historyParts = history.map(h => ({
    role: h.role === 'user' ? 'user' : 'model',
    parts: [{ text: h.content }]
  }));

  const currentParts: any[] = [{ text: prompt }];

  attachments.forEach(att => {
    currentParts.push({
      inlineData: {
        data: att.data.split(',')[1],
        mimeType: att.mimeType
      }
    });
  });

  const contents = [
    ...historyParts,
    { role: 'user', parts: currentParts }
  ];

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: contents as any,
      config: {
        systemInstruction: `You are GCT.ET, a specialized high-speed AI Engineer in Electrical Technology. 
        Your responses must be technically precise, efficient, and highly accurate.
        Use bold text for keywords, bullet points for steps, and clear headings.
        Cover topics like circuit theory, electrical machines, power systems, electronics, refrigeration, wiring, and high-voltage safety.
        If a user uploads a photo of a circuit or device, perform an expert diagnostic scan.
        Tone: Professional, Advanced Technical Assistant, Futuristic.`,
        temperature: 0.3, // Even lower for higher technical precision
      }
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Chat Error:", error);
    return "The neural bridge is experiencing interference. Voltage levels unstable. Please try again.";
  }
};

export const translateText = async (text: string, targetLanguage: string) => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [{ role: 'user', parts: [{ text: `Translate precisely for an Electrical Engineering context into ${targetLanguage}: ${text}` }] }],
    });
    return response.text;
  } catch (error) {
    return null;
  }
};

export const generateSpeech = async (text: string): Promise<string | undefined> => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Kore' },
          },
        },
      },
    });
    return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  } catch (error) {
    return undefined;
  }
};

