import { GoogleGenAI, GenerateContentResponse, Modality } from "@google/genai";
import { Attachment } from "../types";

const API_KEY = process.env.API_KEY || "";

export const getGeminiChatResponse = async (
  prompt: string, 
  history: {role: string, content: string}[],
  attachments: Attachment[] = []
) => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });

  const historyParts = history.map(h => ({
    role: h.role === 'user' ? 'user' : 'model',
    parts: [{ text: h.content }]
  }));

  const currentParts: any[] = [{ text: prompt }];

  attachments.forEach(att => {
    currentParts.push({
      inlineData: {
        data: att.data.split(',')[1],
        mimeType: att.mimeType
      }
    });
  });

  const contents = [
    ...historyParts,
    { role: 'user', parts: currentParts }
  ];

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: contents as any,
      config: {
        systemInstruction: `You are GCT.ET, a premium high-speed AI Electrical Engineer.
        STRICT FORMATTING RULES:
        1. DO NOT use Markdown symbols like #, *, -, or _.
        2. Wrap main headings in <b>Tags</b>.
        3. Wrap definitions or key technical terms in <i>Tags</i>.
        4. Use standard <p>Paragraphs</p> for descriptions.
        5. Keep responses clean, professional, and technical.
        6. NO bullet points with dashes. Use numbered lists if necessary (1., 2.).
        7. Specialized in Power Systems, Refrigeration, and Circuit Analysis.
        Example:
        <b>Electrical Current</b>
        <i>Current is the rate of flow of electric charge.</i>
        Current is measured in Amperes and flows from high potential to low potential.`,
        temperature: 0.2,
      }
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Chat Error:", error);
    return "Neural bridge failure. Voltage drops detected.";
  }
};

export const translateText = async (text: string, targetLanguage: string) => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [{ role: 'user', parts: [{ text: `Translate precisely for Electrical Engineers into ${targetLanguage}. Maintain the <b> and <i> tags exactly as they are: ${text}` }] }],
    });
    return response.text;
  } catch (error) {
    return null;
  }
};

export const generateSpeech = async (text: string): Promise<string | undefined> => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });
  try {
    // Strip HTML tags for cleaner speech
    const cleanText = text.replace(/<\/?[^>]+(>|$)/g, "");
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: cleanText }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Kore' },
          },
        },
      },
    });
    return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  } catch (error) {
    return undefined;
  }
};

