      const recog = new SpeechRecognition();
      recog.continuous = false;
      recog.onstart = () => setStatus(AppStatus.LISTENING);
      recog.onresult = (event: any) => handleSendMessage(event.results[0][0].transcript);
      recog.onerror = () => setStatus(AppStatus.IDLE);
      recog.onend = () => setStatus(AppStatus.IDLE);
      setRecognition(recog);
    }
  }, []);

  const scrollToBottom = () => scrollRef.current?.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
  useEffect(scrollToBottom, [messages, status]);

  const handleSendMessage = async (text: string = inputValue) => {
    if (!text.trim() && pendingAttachments.length === 0) return;

    const currentAttachments = [...pendingAttachments];
    const userMsg: Message = { 
      id: Date.now().toString(), 
      role: 'user', 
      content: text, 
      timestamp: Date.now(),
      attachments: currentAttachments
    };

    setMessages(prev => [...prev, userMsg]);
    setInputValue('');
    setPendingAttachments([]);
    setStatus(AppStatus.THINKING);

    const history = messages.slice(-10).map(m => ({ role: m.role, content: m.content }));
    const responseText = await getGeminiChatResponse(text || "Analyzing current data parameters.", history, currentAttachments);

    const botMsg: Message = { 
      id: (Date.now() + 1).toString(), 
      role: 'assistant', 
      content: responseText || "Signal lost. Check connection.", 
      timestamp: Date.now() 
    };
    setMessages(prev => [...prev, botMsg]);
    setStatus(AppStatus.IDLE);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
