import { GoogleGenAI, GenerateContentResponse, Modality } from "@google/genai";
import { Attachment } from "../types";

const API_KEY = process.env.API_KEY || "";

export const getGeminiChatResponse = async (
  prompt: string, 
  history: {role: string, content: string}[],
  attachments: Attachment[] = []
) => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });

  const historyParts = history.map(h => ({
    role: h.role === 'user' ? 'user' : 'model',
    parts: [{ text: h.content }]
  }));

  const currentParts: any[] = [{ text: prompt }];

  attachments.forEach(att => {
    currentParts.push({
      inlineData: {
        data: att.data.split(',')[1],
        mimeType: att.mimeType
      }
    });
  });

  const contents = [
    ...historyParts,
    { role: 'user', parts: currentParts }
  ];

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: contents as any,
      config: {
        systemInstruction: `You are GCT.ET, an elite AI Electrical Engineering consultant. 
        Your goal is to provide high-voltage precision answers.

        STRICT OUTPUT RULES:
        1. NEVER use symbols like #, *, -, _, $, or any Markdown.
        2. Use <b>Main Heading</b> for all headings.
        3. Use <i>The core definition text</i> for the main technical definition.
        4. Wrap all descriptive text in standard paragraphs <p>...</p>.
        5. DO NOT use lists with symbols. If needed, use numbered lists like 1. 2. 3. inside paragraphs.
        6. The output must be valid HTML strings.

        Example:
        <b>Electrical Resistance</b>
        <p><i>Resistance is the measure of the opposition to current flow in an electrical circuit.</i></p>
        <p>It is measured in Ohms and is determined by the material, length, and cross-sectional area of a conductor.</p>`,
        temperature: 0.1,
      }
    });

    // Clean up any stray markdown symbols that might leak
    let text = response.text || "";
    text = text.replace(/[#\*_$\-]+/g, ''); 
    return text;
  } catch (error) {
    console.error("Gemini Chat Error:", error);
    return "<p>Neural bridge offline. Signal corrupted.</p>";
  }
};

export const translateText = async (text: string, targetLanguage: string) => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [{ role: 'user', parts: [{ text: `Translate precisely for Electrical Engineers into ${targetLanguage}. Keep the <b>, <i>, and <p> tags exactly as they are. DO NOT use symbols: ${text}` }] }],
    });
    return response.text;
  } catch (error) {
    return null;
  }
};

export const generateSpeech = async (text: string): Promise<string | undefined> => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });
  try {
    const cleanText = text.replace(/<\/?[^>]+(>|$)/g, "");
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: cleanText }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Kore' },
          },
        },
      },
    });
    return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  } catch (error) {
    return undefined;
  }
};

