    name: '', city: '', address: '', email: '', institution: '', profilePic: '', idNumber: 'GCT-' + Math.floor(1000 + Math.random() * 9000)
  });

  const scrollRef = useRef<HTMLDivElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const [isCameraActive, setIsCameraActive] = useState(false);
  const [recognition, setRecognition] = useState<any>(null);

  const t = UI_TRANSLATIONS[appLang];

  useEffect(() => {
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
      const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
      const recog = new SpeechRecognition();
      recog.continuous = false;
      recog.onstart = () => setStatus(AppStatus.LISTENING);
      recog.onresult = (event: any) => handleSendMessage(event.results[0][0].transcript);
      recog.onerror = () => setStatus(AppStatus.IDLE);
      recog.onend = () => setStatus(AppStatus.IDLE);
      setRecognition(recog);
    }
  }, []);

  const scrollToBottom = () => scrollRef.current?.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
  useEffect(scrollToBottom, [messages, status]);

  const handleSendMessage = async (text: string = inputValue) => {
    if (!text.trim() && pendingAttachments.length === 0) return;

    const currentAttachments = [...pendingAttachments];
    const userMsg: Message = { 
      id: Date.now().toString(), 
      role: 'user', 
      content: text, 
      timestamp: Date.now(),
      attachments: currentAttachments
    };

    setMessages(prev => [...prev, userMsg]);
    setInputValue('');
    setPendingAttachments([]);
    setStatus(AppStatus.THINKING);

    const history = messages.slice(-10).map(m => ({ role: m.role, content: m.content }));
    const responseText = await getGeminiChatResponse(text || "Analyzing current data parameters.", history, currentAttachments);

    const botMsg: Message = { 
      id: (Date.now() + 1).toString(), 
      role: 'assistant', 
      content: responseText || "Signal lost. Check connection.", 
      timestamp: Date.now() 
    };
    setMessages(prev => [...prev, botMsg]);
    setStatus(AppStatus.IDLE);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setPendingAttachments(prev => [...prev, { data: reader.result as string, mimeType: file.type }]);
      reader.readAsDataURL(file);
    }
  };

  const handleListen = async (text: string) => {
    setStatus(AppStatus.SPEAKING);
    const audio = await generateSpeech(text);
    if (audio) {
      const ctx = audioContextRef.current || (audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 }));
      const binary = atob(audio);
      const bytes = new Uint8Array(binary.length);
      for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
      const dataInt16 = new Int16Array(bytes.buffer);
      const buffer = ctx.createBuffer(1, dataInt16.length, 24000);
      buffer.getChannelData(0).set(Array.from(dataInt16).map(v => v / 32768.0));
      const source = ctx.createBufferSource();
      source.buffer = buffer;
      source.connect(ctx.destination);
      source.onended = () => setStatus(AppStatus.IDLE);
      source.start();
    } else setStatus(AppStatus.IDLE);
  };

