              <div className={`absolute top-0 left-0 w-2 h-full ${msg.role === 'user' ? 'bg-amber-400' : 'bg-cyan-500/30'} animate-pulse`}></div>

              {msg.attachments?.map((att, i) => (
                <img key={i} src={att.data} className="w-full h-56 object-cover rounded-[2rem] mb-5 border border-white/10 shadow-lg" />
              ))}

              <div className={`bot-message text-[15.5px] ${msg.role === 'assistant' ? 'leading-relaxed' : 'font-semibold'}`} 
                   dangerouslySetInnerHTML={{ __html: msg.translation || msg.content }}>
              </div>

              {msg.role === 'assistant' && (
                <div className="mt-6 flex items-center gap-8 opacity-60 border-t border-white/5 pt-5">
                  <button onClick={() => handleListen(msg.translation || msg.content)} className="flex items-center gap-2.5 text-[10px] font-bold uppercase font-futuristic hover:opacity-100 hover:text-amber-400 transition-all hover:scale-105">
                    <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M15.536 8.464a5 5 0 010 7.072M18.364 5.636a9 9 0 010 12.728M12 9v6m-4-3h1" strokeWidth={2}/></svg>
                    Listen
                  </button>
                  <div className="relative group">
                    <button className="flex items-center gap-2.5 text-[10px] font-bold uppercase font-futuristic hover:opacity-100 hover:text-amber-400 transition-all hover:scale-105">Translate</button>
                    <div className="absolute bottom-full left-0 mb-5 hidden group-hover:grid grid-cols-2 gap-3 bg-black/98 border border-white/10 p-4 rounded-3xl backdrop-blur-3xl z-50 min-w-[180px] shadow-[0_20px_100px_rgba(0,0,0,1)]">
                      {SUPPORTED_LANGUAGES.map(l => (
                        <button key={l.code} onClick={() => translateText(msg.content, l.code).then(txt => txt && setMessages(prev => prev.map(m => m.id === msg.id ? {...m, translation: txt, lang: l.name} : m)))} className="px-5 py-3 text-[12px] hover:bg-amber-500/20 rounded-2xl text-white text-left font-semibold transition-all">{l.name}</button>
                      ))}
                    </div>
                  </div>
                </div>
              )}
            </div>
            <span className="text-[10px] opacity-25 mt-3 font-futuristic tracking-[0.25em] px-6 uppercase font-bold">{new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
          </div>
        ))}
      </main>

      {/* Input Module */}
      <div className={`relative z-30 px-6 pt-5 pb-16 border-t backdrop-blur-[50px] transition-colors duration-500 ${theme === 'dark' ? 'bg-black/80 border-white/5' : 'bg-white/95 border-gray-100'}`}>
        {pendingAttachments.length > 0 && (
          <div className="flex gap-4 mb-5 overflow-x-auto pb-3 scrollbar-hide">
            {pendingAttachments.map((att, i) => (
              <div key={i} className="relative shrink-0 animate-in zoom-in-95 duration-500">
                <img src={att.data} className="w-20 h-20 rounded-[1.75rem] object-cover border-2 border-amber-500/40 shadow-2xl" />
                <button onClick={() => setPendingAttachments(p => p.filter((_, j) => i !== j))} className="absolute -top-3 -right-3 bg-red-500 rounded-full p-2 shadow-2xl border-2 border-white/20 hover:scale-110 active:scale-90 transition-all"><svg className="w-4 h-4 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M6 18L18 6M6 6l12 12" strokeWidth={3}/></svg></button>
              </div>
            ))}
          </div>
        )}

        <div className="flex items-center gap-5">
          <div className="flex gap-2">
            <button onClick={() => fileInputRef.current?.click()} className={`p-4 rounded-[1.75rem] transition-all hover:bg-amber-500/15 hover:scale-105 active:scale-95 ${theme === 'dark' ? 'bg-white/5 border border-white/5 shadow-inner' : 'bg-gray-100 border border-gray-200'}`}>
              <svg className="w-6 h-6 text-amber-500" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M15.172 7l-6.586 6.586a2 2 0 102.828 2.828l6.414-6.586a4 4 0 00-5.656-5.656l-6.415 6.585a6 6 0 108.486 8.486L20.5 13" strokeWidth={2}/></svg>
              <input type="file" ref={fileInputRef} onChange={handleFileUpload} hidden />
            </button>
            <button onClick={() => { setIsCameraActive(true); navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } }).then(s => { if(videoRef.current) videoRef.current.srcObject = s; }); }} className={`p-4 rounded-[1.75rem] transition-all hover:bg-amber-500/15 hover:scale-105 active:scale-95 ${theme === 'dark' ? 'bg-white/5 border border-white/5 shadow-inner' : 'bg-gray-100 border border-gray-200'}`}>
              <svg className="w-6 h-6 text-amber-500" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" strokeWidth={2}/></svg>
            </button>
          </div>

          <div className="flex-1 relative">
            <input 
              value={inputValue} 
              onChange={e => setInputValue(e.target.value)}
              onKeyDown={e => e.key === 'Enter' && handleSendMessage()}
              placeholder={t.inputHint}
              className={`w-full py-5 px-8 rounded-[2rem] text-base transition-all focus:ring-4 focus:outline-none ${theme === 'dark' ? 'bg-[#11111a] border border-white/5 text-white focus:ring-amber-500/10' : 'bg-gray-100 border border-gray-200 focus:ring-amber-500/10 shadow-inner'}`}
            />
          </div>

          <button 
            onClick={() => handleSendMessage()}
            className={`w-16 h-16 flex items-center justify-center rounded-[2rem] transition-all shadow-[0_15px_40px_rgba(251,191,36,0.2)] group hover:scale-105 active:scale-90 ${theme === 'dark' ? 'bg-amber-500 hover:bg-amber-400' : 'bg-amber-600 hover:bg-amber-500'} disabled:opacity-10`}
          >
            <svg className="w-7 h-7 text-black group-hover:rotate-[15deg] transition-all" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M13 10V3L4 14h7v7l9-11h-7z" strokeWidth={2.5}/></svg>
          </button>
        </div>
      </div>

      {/* Glowing Animated Footer */}
      <footer className={`absolute bottom-0 left-0 w-full z-40 px-8 py-4 flex items-center justify-between border-t transition-all ${theme === 'dark' ? 'bg-black/95 border-white/5' : 'bg-white/98 border-gray-100 shadow-[0_-15px_40px_rgba(0,0,0,0.05)]'}`}>
         <div className="flex items-center gap-5 group">
            <div className="relative">
              <div className="absolute inset-0 bg-amber-500 rounded-full animate-ping opacity-20"></div>
              <div className="w-2.5 h-2.5 rounded-full bg-amber-500 animate-pulse relative z-10 shadow-[0_0_12px_#fbbf24]"></div>
            </div>
            <span className="text-[12px] font-futuristic tracking-[0.4em] opacity-40 uppercase group-hover:opacity-100 group-hover:text-amber-400 transition-all font-bold">{t.created}</span>
         </div>
         <a 
            href="https://www.facebook.com/share/1HnU5FCMGs/" 
            target="_blank" 
            rel="noopener noreferrer"
            className="p-3 rounded-2xl bg-amber-500/5 hover:bg-amber-500/15 text-amber-500 transition-all hover:scale-110 active:scale-95 shadow-inner border border-amber-500/10"
          >
            <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 24 24"><path d="M24 12.073c0-6.627-5.373-12-12-12s-12 5.373-12 12c0 5.99 4.388 10.954 10.125 11.854v-8.385H7.078v-3.47h3.047V9.43c0-3.007 1.792-4.669 4.533-4.669 1.312 0 2.686.235 2.686.235v2.953H15.83c-1.491 0-1.956.925-1.956 1.874v2.25h3.328l-.532 3.47h-2.796v8.385C19.612 23.027 24 18.062 24 12.073z"/></svg>
          </a>
      </footer>

      {/* Settings Overlay */}
      {showSettings && (
        <div className="absolute inset-0 z-[120] flex items-end animate-in slide-in-from-bottom-full duration-600">
          <div className="w-full h-4/5 bg-[#050508] rounded-t-[5rem] p-12 border-t border-amber-500/20 shadow-[0_-40px_120px_rgba(0,0,0,1)] overflow-y-auto custom-scroll">
            <div className="w-20 h-2 bg-white/5 rounded-full mx-auto mb-12"></div>
            <div className="flex justify-between items-center mb-16">
              <h3 className="font-futuristic text-amber-400 tracking-[0.6em] text-xl font-bold uppercase">{t.settings}</h3>
              <button onClick={() => setShowSettings(false)} className="text-white/30 hover:text-amber-400 hover:rotate-180 transition-all duration-500 active:scale-90"><svg className="w-12 h-12" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M6 18L18 6M6 6l12 12" strokeWidth={1.2}/></svg></button>
            </div>

            <div className="space-y-12">
              <div className="p-10 bg-white/5 rounded-[4rem] border border-white/5 flex flex-col gap-8 shadow-inner">
                <span className="text-[11px] font-futuristic uppercase tracking-[0.4em] opacity-40 font-bold">{t.theme}</span>
                <div className="grid grid-cols-2 bg-black/40 p-2.5 rounded-[2.5rem] border border-white/5">
                  <button onClick={() => setTheme('dark')} className={`py-5 rounded-[2rem] text-[12px] font-futuristic transition-all ${theme === 'dark' ? 'bg-amber-500 text-black shadow-[0_15px_40px_rgba(251,191,36,0.3)] font-bold' : 'opacity-20 hover:opacity-40'}`}>DARK</button>
                  <button onClick={() => setTheme('light')} className={`py-5 rounded-[2rem] text-[12px] font-futuristic transition-all ${theme === 'light' ? 'bg-amber-500 text-black shadow-[0_15px_40px_rgba(251,191,36,0.3)] font-bold' : 'opacity-20 hover:opacity-40'}`}>LIGHT</button>
                </div>
              </div>

              <div className="p-10 bg-white/5 rounded-[4rem] border border-white/5 flex flex-col gap-8 shadow-inner">
                <span className="text-[11px] font-futuristic uppercase tracking-[0.4em] opacity-40 font-bold">{t.lang}</span>
                <div className="grid grid-cols-3 gap-4">
                  {SUPPORTED_LANGUAGES.map(lang => (
                    <button 
                      key={lang.code} 
                      onClick={() => setAppLang(lang.code)} 
                      className={`py-4 rounded-[1.5rem] text-[12px] font-bold border transition-all hover:scale-105 active:scale-95 ${appLang === lang.code ? 'bg-cyan-600 border-cyan-400 shadow-[0_10px_30px_rgba(8,145,178,0.4)] text-white' : 'bg-black/40 border-white/10 opacity-40'}`}
                    >
                      {lang.name}
                    </button>
                  ))}
                </div>
              </div>

              <p className="text-[11px] text-center opacity-10 font-futuristic tracking-[1em] pt-20 uppercase font-black">GCT.ET NEURAL V6.5</p>
            </div>
          </div>
        </div>
      )}

      {/* ID Profile Modal */}
      {showProfileModal && (
        <div className="absolute inset-0 z-[150] flex items-center justify-center p-6 bg-black/98 backdrop-blur-[150px] animate-in fade-in duration-600">
          <div className="w-full max-w-sm">
            {!profile ? (
              <div className="bg-[#08080c] p-12 rounded-[5rem] border border-amber-500/20 space-y-8 shadow-[0_0_150px_rgba(251,191,36,0.15)] relative overflow-hidden">
                <div className="absolute -top-10 -right-10 w-40 h-40 bg-amber-500/10 blur-[80px] rounded-full"></div>
                <h2 className="font-futuristic text-center text-amber-400 text-xs tracking-[0.5em] uppercase font-bold">{t.idTitle}</h2>
                <div className="space-y-4">
                  <input placeholder="ENGINEER NAME" className="w-full bg-white/5 border border-white/5 p-6 rounded-[2rem] text-[12px] font-bold tracking-widest outline-none focus:border-amber-500/40 focus:bg-white/10 transition-all shadow-inner" onChange={e => setTempProfile(p => ({...p, name: e.target.value}))} />
                  <input placeholder="INSTITUTE / SECTOR" className="w-full bg-white/5 border border-white/5 p-6 rounded-[2rem] text-[12px] font-bold tracking-widest outline-none focus:border-amber-500/40 focus:bg-white/10 transition-all shadow-inner" onChange={e => setTempProfile(p => ({...p, institution: e.target.value}))} />
                  <input placeholder="GMAIL / EMAIL" className="w-full bg-white/5 border border-white/5 p-6 rounded-[2rem] text-[12px] font-bold tracking-widest outline-none focus:border-amber-500/40 focus:bg-white/10 transition-all shadow-inner" onChange={e => setTempProfile(p => ({...p, email: e.target.value}))} />
                  <input placeholder={t.city} className="w-full bg-white/5 border border-white/5 p-6 rounded-[2rem] text-[12px] font-bold tracking-widest outline-none focus:border-amber-500/40 focus:bg-white/10 transition-all shadow-inner" onChange={e => setTempProfile(p => ({...p, city: e.target.value}))} />
                  <input placeholder={t.address} className="w-full bg-white/5 border border-white/5 p-6 rounded-[2rem] text-[12px] font-bold tracking-widest outline-none focus:border-amber-500/40 focus:bg-white/10 transition-all shadow-inner" onChange={e => setTempProfile(p => ({...p, address: e.target.value}))} />

                  <div className="flex justify-center py-4">
                    <label className="cursor-pointer group flex flex-col items-center gap-4">
                      <div className="w-24 h-24 rounded-[2.5rem] bg-amber-500/5 border-2 border-dashed border-amber-500/30 flex items-center justify-center group-hover:bg-amber-500/10 transition-all shadow-2xl relative overflow-hidden">
                        {tempProfile.profilePic ? <img src={tempProfile.profilePic} className="w-full h-full object-cover rounded-[2.3rem]" /> : <svg className="w-10 h-10 opacity-20 text-amber-500" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M12 9v3m0 0v3m0-3h3m-3 0H9m12 0a9 9 0 11-18 0 9 9 0 0118 0z" strokeWidth={1.5}/></svg>}
                      </div>
                      <span className="text-[11px] font-futuristic opacity-30 group-hover:opacity-100 uppercase font-bold tracking-widest">UPLOAD PIC</span>
                      <input type="file" accept="image/*" hidden onChange={e => {
                        const f = e.target.files?.[0];
                        if(f) { const r = new FileReader(); r.onloadend = () => setTempProfile(p => ({...p, profilePic: r.result as string})); r.readAsDataURL(f); }
                      }} />
                    </label>
                  </div>

                  <button onClick={() => {if(tempProfile.name) setProfile(tempProfile as UserProfile)}} className="w-full bg-amber-500 p-7 rounded-[2.5rem] font-futuristic text-sm tracking-[0.6em] text-black shadow-[0_20px_60px_rgba(251,191,36,0.25)] hover:scale-105 active:scale-95 transition-all font-black">{t.genId}</button>
                </div>
                <button onClick={() => setShowProfileModal(false)} className="w-full text-[11px] opacity-20 font-futuristic text-center mt-8 tracking-[0.5em] hover:opacity-100 uppercase font-bold">Abort Sync</button>
              </div>
            ) : (
              <div id="id-card-capture" className="relative animate-in zoom-in-95 duration-700">
                <div className="w-full aspect-[1.586/1] bg-gradient-to-br from-[#050508] via-[#0d0d16] to-black rounded-[4rem] border border-amber-500/40 p-10 shadow-[0_0_120px_rgba(251,191,36,0.15)] flex flex-col justify-between relative overflow-hidden border-2">
                   {/* Cyber Decor */}
                   <div className="absolute top-0 right-0 w-40 h-40 bg-amber-500/5 blur-[100px] rounded-full"></div>
                   <div className="absolute -bottom-10 -left-10 w-40 h-40 bg-cyan-500/5 blur-[100px] rounded-full"></div>

                   <div className="flex justify-between items-start z-10">
                     <div className="flex gap-8">
                       <div className="w-24 h-24 rounded-[2.5rem] border-2 border-amber-500/40 overflow-hidden bg-black p-1.5 shadow-[0_20px_50px_rgba(0,0,0,0.5)]">
                         {profile.profilePic ? <img src={profile.profilePic} className="w-full h-full object-cover rounded-[2.2rem]" /> : <div className="w-full h-full flex items-center justify-center opacity-10 text-amber-500"><svg className="w-12 h-12" fill="currentColor" viewBox="0 0 20 20"><path d="M10 9a3 3 0 100-6 3 3 0 000 6zm-7 9a7 7 0 1114 0H3z" /></svg></div>}
                       </div>
                       <div className="space-y-2 pt-2">
                         <h3 className="font-futuristic text-white text-[16px] tracking-[0.25em] uppercase font-black">{profile.name}</h3>
                         <p className="text-[10px] text-amber-500 opacity-90 uppercase font-futuristic tracking-[0.1em] font-bold">{profile.institution}</p>
                         <div className="pt-4 space-y-2">
                            <p className="text-[9px] text-white/40 font-bold flex items-center gap-3"><span className="w-1.5 h-1.5 bg-amber-400 rounded-full shadow-[0_0_6px_#fbbf24]"></span> {profile.email}</p>
                            <p className="text-[9px] text-white/40 font-bold flex items-center gap-3"><span className="w-1.5 h-1.5 bg-cyan-400 rounded-full shadow-[0_0_6px_#22d3ee]"></span> {profile.city}</p>
                         </div>
                       </div>
                     </div>
                     <Logo />
                   </div>

                   <div className="flex justify-between items-end border-t border-white/5 pt-8 z-10">
                     <div className="space-y-2">
                        <p className="text-[8px] font-futuristic tracking-[0.6em] text-white/40 uppercase font-black">GCT ELECTRICAL SECTOR</p>
                        <p className="text-[10px] font-futuristic text-amber-500 tracking-[0.4em] font-black">{profile.idNumber}</p>
                     </div>
                     <div className="text-right">
                        <p className="text-[9px] font-bold text-white/30 tracking-[0.05em] uppercase">{profile.address}</p>
                        <p className="text-[11px] font-futuristic text-cyan-400 mt-2 uppercase tracking-[0.3em] animate-pulse font-black drop-shadow-[0_0_8px_rgba(34,211,238,0.5)]">Certified Node</p>
                     </div>
                   </div>

                   {/* Scanning Laser Beam */}
                   <div className="absolute inset-0 pointer-events-none bg-gradient-to-b from-transparent via-amber-500/20 to-transparent h-2 w-full animate-[idscan_3.5s_linear_infinite] shadow-[0_0_30px_rgba(251,191,36,0.3)]"></div>
                </div>

                <div className="flex gap-5 mt-12">
                  <button onClick={() => window.print()} className="flex-1 bg-amber-500/15 border border-amber-500/40 p-6 rounded-[2.5rem] font-futuristic text-[12px] tracking-widest hover:bg-amber-500/40 transition-all text-amber-400 font-black shadow-2xl active:scale-95">{t.download}</button>
                  <button onClick={() => setProfile(null)} className="flex-1 bg-white/5 border border-white/10 p-6 rounded-[2.5rem] font-futuristic text-[12px] tracking-widest hover:bg-white/10 transition-all font-black shadow-2xl active:scale-95">{t.rescan}</button>
                </div>
                <button onClick={() => setShowProfileModal(false)} className="w-full text-[12px] opacity-20 font-futuristic text-center mt-12 tracking-[0.8em] hover:opacity-100 uppercase font-black transition-all">TERMINATE ACCESS</button>
              </div>
            )}
          </div>
        </div>
      )}

      {/* Advanced Sync Status */}
      {status === AppStatus.THINKING && (
        <div className="absolute top-28 left-1/2 -translate-x-1/2 z-[130] bg-black/60 border border-amber-500/30 px-12 py-4 rounded-full backdrop-blur-[60px] shadow-[0_0_100px_rgba(251,191,36,0.3)] animate-pulse flex items-center gap-6">
           <div className="flex gap-2">
              <div className="w-2 h-2 bg-amber-400 rounded-full animate-bounce [animation-duration:1s]"></div>
              <div className="w-2 h-2 bg-amber-400 rounded-full animate-bounce [animation-duration:1s] [animation-delay:0.2s]"></div>
              <div className="w-2 h-2 bg-amber-400 rounded-full animate-bounce [animation-duration:1s] [animation-delay:0.4s]"></div>
           </div>
           <span className="text-[12px] font-futuristic tracking-[0.8em] text-amber-400 uppercase font-black">Syncing Neural Core</span>
        </div>
      )}

      <style>{`
        @keyframes idscan {
          0% { transform: translateY(-100%); opacity: 0; }
          10%, 90% { opacity: 1; }
          100% { transform: translateY(800%); opacity: 0; }
        }
        @media print {
          body * { visibility: hidden; }
          #id-card-capture, #id-card-capture * { visibility: visible; }
          #id-card-capture { position: fixed; left: 50%; top: 50%; transform: translate(-50%, -50%) scale(3.5); }
        }
        .scrollbar-hide::-webkit-scrollbar { display: none; }
        .scrollbar-hide { -ms-overflow-style: none; scrollbar-width: none; }
        .custom-scroll::-webkit-scrollbar { width: 6px; }
        .custom-scroll::-webkit-scrollbar-thumb { background: rgba(251, 191, 36, 0.2); border-radius: 10px; }
      `}</style>
    </div>
  );
};

export default App;

export interface Attachment {
  data: string;
  mimeType: string;
}

export interface Message {
  id: string;
  role: 'user' | 'assistant';
  content: string;
  timestamp: number;
  translation?: string;
  lang?: string;
  attachments?: Attachment[];
  isImage?: boolean;
}

export enum AppStatus {
  IDLE = 'IDLE',
  LISTENING = 'LISTENING',
  THINKING = 'THINKING',
  SPEAKING = 'SPEAKING',
  TRANSLATING = 'TRANSLATING'
}

export interface UserProfile {
  name: string;
  city: string;
  address: string;
  email: string;
  institution: string;
  profilePic: string;
  idNumber: string;
}

export type Theme = 'dark' | 'light';
export type AppLang = 'English' | 'Urdu' | 'Hindi' | 'Punjabi' | 'Pashto' | 'Chinese';

export type PrimaryColor = 'blue' | 'purple' | 'green' | 'pink' | 'orange';

