                  {(Object.keys(COLOR_THEMES) as PrimaryColor[]).map(c => (
                    <button 
                      key={c}
                      onClick={() => setPrimaryColor(c)}
                      className={`w-10 h-10 rounded-full border-2 transition-all hover:scale-110 flex items-center justify-center ${primaryColor === c ? 'border-white scale-110 shadow-lg' : 'border-transparent'}`}
