              {/* Language Selector */}
              <div className="p-6 bg-white/5 rounded-3xl border border-white/5 flex flex-col gap-5">
                <span className="text-[10px] font-futuristic uppercase tracking-[0.2em] opacity-40">{t.lang}</span>
                <div className="grid grid-cols-3 gap-2">
                  {SUPPORTED_LANGUAGES.map(lang => (
                    <button key={lang.code} onClick={() => setAppLang(lang.code)} className={`py-3 rounded-xl text-[10px] font-medium border transition-all ${appLang === lang.code ? 'bg-white/10 border-white/20' : 'bg-black/20 border-transparent opacity-40'}`}>{lang.name}</button>
                  ))}
                </div>
              </div>

              <p className="text-[9px] text-center opacity-10 font-futuristic tracking-[0.8em] pt-10 uppercase">GCT NEURAL V7.2</p>
            </div>
          </div>
        </div>
      )}

      {/* Camera UI */}
      {isCameraActive && (
        <div className="absolute inset-0 z-[130] bg-black flex flex-col items-center justify-center animate-in fade-in duration-500">
          <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover" />
          <div className="absolute bottom-10 flex gap-10 items-center">
            <button onClick={() => { (videoRef.current?.srcObject as MediaStream).getTracks().forEach(t => t.stop()); setIsCameraActive(false); }} className="p-4 bg-white/10 rounded-full border border-white/20 text-white"><svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M6 18L18 6M6 6l12 12" strokeWidth={2}/></svg></button>
            <button 
              onClick={() => {
                const c = document.createElement('canvas');
                c.width = videoRef.current!.videoWidth; c.height = videoRef.current!.videoHeight;
                c.getContext('2d')!.drawImage(videoRef.current!, 0, 0);
                setPendingAttachments(p => [...p, { data: c.toDataURL('image/jpeg'), mimeType: 'image/jpeg' }]);
                (videoRef.current?.srcObject as MediaStream).getTracks().forEach(t => t.stop()); setIsCameraActive(false);
              }}
              className="w-16 h-16 bg-white rounded-full border-4 flex items-center justify-center shadow-2xl active:scale-90 transition-all"
              style={{ borderColor: activeColor.hex }}
            ></button>
          </div>
        </div>
      )}

      {/* Sync Status Overlay */}
      {status === AppStatus.THINKING && (
        <div className="absolute top-20 left-1/2 -translate-x-1/2 z-[100] bg-black/60 border border-white/5 px-8 py-2.5 rounded-full backdrop-blur-3xl shadow-2xl animate-pulse flex items-center gap-4">
           <div className="flex gap-1.5">
              <div className="w-1.5 h-1.5 rounded-full animate-bounce" style={{ backgroundColor: activeColor.hex }}></div>
              <div className="w-1.5 h-1.5 rounded-full animate-bounce [animation-delay:0.2s]" style={{ backgroundColor: activeColor.hex }}></div>
              <div className="w-1.5 h-1.5 rounded-full animate-bounce [animation-delay:0.4s]" style={{ backgroundColor: activeColor.hex }}></div>
           </div>
           <span className="text-[10px] font-futuristic tracking-[0.5em] uppercase" style={{ color: activeColor.hex }}>Processing</span>
        </div>
      )}

      {/* ID Maker Modal (Simplified fields for brevity, maintaining functionality) */}
      {showProfileModal && (
        <div className="absolute inset-0 z-[150] flex items-center justify-center p-6 bg-black/98 backdrop-blur-2xl animate-in fade-in duration-500">
           <div className="bg-white/5 p-8 rounded-[3rem] border border-white/10 w-full max-w-sm space-y-6">
              {!profile ? (
                <>
                  <h2 className="font-futuristic text-center text-xs tracking-widest uppercase" style={{ color: activeColor.hex }}>{t.idTitle}</h2>
                  <div className="space-y-3">
                    <input placeholder="ENGINEER NAME" className="w-full bg-white/5 border border-white/10 p-4 rounded-2xl text-[11px] outline-none" onChange={e => setTempProfile(p => ({...p, name: e.target.value}))} />
                    <input placeholder={t.email} className="w-full bg-white/5 border border-white/10 p-4 rounded-2xl text-[11px] outline-none" onChange={e => setTempProfile(p => ({...p, email: e.target.value}))} />
                    <input placeholder={t.city} className="w-full bg-white/5 border border-white/10 p-4 rounded-2xl text-[11px] outline-none" onChange={e => setTempProfile(p => ({...p, city: e.target.value}))} />
                    <button onClick={() => {if(tempProfile.name) setProfile(tempProfile as UserProfile)}} className="w-full p-4 rounded-2xl font-futuristic text-[11px] text-black font-bold tracking-widest" style={{ backgroundColor: activeColor.hex }}>{t.genId}</button>
                  </div>
                  <button onClick={() => setShowProfileModal(false)} className="w-full text-[9px] opacity-20 hover:opacity-100 font-futuristic text-center">CANCEL</button>
                </>
              ) : (
                <div className="relative animate-in zoom-in-95 p-6 rounded-[2.5rem] bg-gradient-to-br from-gray-900 to-black border-2 border-white/10 flex flex-col items-center">
                   <div className="w-20 h-20 rounded-2xl border-2 mb-4 overflow-hidden" style={{ borderColor: activeColor.hex }}>
                     {profile.profilePic ? <img src={profile.profilePic} className="w-full h-full object-cover" /> : <div className="w-full h-full flex items-center justify-center opacity-10" style={{ color: activeColor.hex }}><svg className="w-10 h-10" fill="currentColor" viewBox="0 0 20 20"><path d="M10 9a3 3 0 100-6 3 3 0 000 6zm-7 9a7 7 0 1114 0H3z" /></svg></div>}
                   </div>
                   <h3 className="font-futuristic text-white text-[14px] uppercase tracking-widest mb-1">{profile.name}</h3>
                   <p className="text-[10px] text-white/30 font-futuristic">{profile.idNumber}</p>
                   <div className="w-full border-t border-white/5 mt-6 pt-6 text-[9px] font-futuristic text-center opacity-40 uppercase tracking-[0.2em]">{profile.city} Sector</div>
                   <button onClick={() => setShowProfileModal(false)} className="mt-8 text-[9px] opacity-30 uppercase font-bold tracking-widest">Close</button>
                </div>
              )}
           </div>
        </div>
      )}

      <style>{`
        .scrollbar-hide::-webkit-scrollbar { display: none; }
        .scrollbar-hide { -ms-overflow-style: none; scrollbar-width: none; }
        .custom-scroll::-webkit-scrollbar { width: 5px; }
        .custom-scroll::-webkit-scrollbar-thumb { background: rgba(255, 255, 255, 0.1); border-radius: 10px; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { Message, AppStatus, UserProfile, SUPPORTED_LANGUAGES, ELECTRICAL_TEMPLATES, Theme, AppLang, Attachment, UI_TRANSLATIONS, PrimaryColor, COLOR_THEMES } from './types';
import Logo from './components/Logo';
import { getGeminiChatResponse, generateSpeech } from './services/geminiService';

const App: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [theme, setTheme] = useState<Theme>('dark');
  const [primaryColor, setPrimaryColor] = useState<PrimaryColor>('blue');
  const [appLang, setAppLang] = useState<AppLang>('English');
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [showProfileModal, setShowProfileModal] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [pendingAttachments, setPendingAttachments] = useState<Attachment[]>([]);

  const [tempProfile, setTempProfile] = useState<Partial<UserProfile>>({
    name: '', city: '', email: '', idNumber: 'GCT-' + Math.floor(1000 + Math.random() * 9000)
  });

  const scrollRef = useRef<HTMLDivElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const [isCameraActive, setIsCameraActive] = useState(false);

  const t = UI_TRANSLATIONS[appLang];
  const activeColor = COLOR_THEMES[primaryColor];

  const scrollToBottom = () => scrollRef.current?.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
  useEffect(scrollToBottom, [messages, status]);

  const handleSendMessage = async (text: string = inputValue) => {
    if (!text.trim() && pendingAttachments.length === 0) return;

    const currentAttachments = [...pendingAttachments];
    const userMsg: Message = { 
      id: Date.now().toString(), 
      role: 'user', 
      content: text, 
      timestamp: Date.now(),
      attachments: currentAttachments
    };

    setMessages(prev => [...prev, userMsg]);
    setInputValue('');
    setPendingAttachments([]);
    setStatus(AppStatus.THINKING);

    const history = messages.slice(-10).map(m => ({ role: m.role, content: m.content }));
    const result = await getGeminiChatResponse(text || "Diagnostic analysis.", history, currentAttachments);

    const botMsg: Message = { 
      id: (Date.now() + 1).toString(), 
      role: 'assistant', 
      content: result.content, 
      timestamp: Date.now(),
      isImage: result.isImage,
      attachments: result.imageData ? [{ data: result.imageData, mimeType: 'image/png' }] : undefined
    };
    setMessages(prev => [...prev, botMsg]);
    setStatus(AppStatus.IDLE);
  };

  const handleListen = async (text: string) => {
    setStatus(AppStatus.SPEAKING);
    const audio = await generateSpeech(text);
    if (audio) {
      const ctx = audioContextRef.current || (audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 }));
      const binary = atob(audio);
      const bytes = new Uint8Array(binary.length);
      for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
      const dataInt16 = new Int16Array(bytes.buffer);
      const buffer = ctx.createBuffer(1, dataInt16.length, 24000);
      buffer.getChannelData(0).set(Array.from(dataInt16).map(v => v / 32768.0));
      const source = ctx.createBufferSource();
      source.buffer = buffer;
      source.connect(ctx.destination);
      source.onended = () => setStatus(AppStatus.IDLE);
      source.start();
    } else setStatus(AppStatus.IDLE);
  };

  return (
    <div 
      className={`flex flex-col h-screen max-w-md mx-auto relative overflow-hidden transition-all duration-700 ${theme === 'dark' ? 'bg-[#050505]' : 'bg-[#fcfdfd]'}`}
      style={{ '--theme-color': activeColor.hex, '--theme-glow': activeColor.shadow } as any}
    >

      {/* Dynamic Energy Background */}
      <div className="absolute inset-0 z-0 pointer-events-none">
        <div className={`absolute -inset-[50%] opacity-[0.05] animate-[pulse_15s_infinite]`} style={{ background: `radial-gradient(circle at center, ${activeColor.hex}, transparent 70%)` }}></div>
        <div className="absolute inset-0 backdrop-blur-[120px]"></div>
      </div>

      {/* Header - Professional & Tight */}
      <header className={`relative z-20 px-6 py-4 flex items-center justify-between border-b transition-all duration-500 ${theme === 'dark' ? 'border-white/5 bg-black/40' : 'border-gray-100 bg-white/60'}`}>
        <Logo color={primaryColor} />
        <div className="flex items-center gap-4">
           <button onClick={() => setShowSettings(true)} className="p-2 transition-all hover:scale-110 active:scale-90" style={{ color: activeColor.hex }}>
             <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M12 6V4m0 2a2 2 0 100 4m0-4a2 2 0 110 4m-6 8a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4m6 6v10m6-2a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4" strokeWidth={2}/></svg>
           </button>
           <button onClick={() => setShowProfileModal(true)} className={`p-1 rounded-xl border-2 transition-all hover:rotate-3 shadow-lg`} style={{ borderColor: `${activeColor.hex}44`, backgroundColor: `${activeColor.hex}11` }}>
            {profile?.profilePic ? <img src={profile.profilePic} className="w-8 h-8 rounded-lg object-cover" /> : <svg className="w-6 h-6" style={{ color: activeColor.hex }} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" /></svg>}
           </button>
        </div>
      </header>

      {/* Chat Space */}
      <main ref={scrollRef} className="flex-1 overflow-y-auto z-10 p-6 space-y-8 scroll-smooth pb-32">
        {messages.length === 0 && (
          <div className="py-12 space-y-10 animate-in fade-in duration-1000">
            <div className="text-center space-y-3">
              <h2 className="font-futuristic text-2xl font-bold tracking-[0.3em] uppercase drop-shadow-md" style={{ color: activeColor.hex }}>{t.status}</h2>
              <div className="flex items-center justify-center gap-3 opacity-50">
                <span className="w-8 h-[1px] bg-white/20"></span>
                <p className="text-[10px] uppercase tracking-[0.5em] font-semibold">{t.subStatus}</p>
                <span className="w-8 h-[1px] bg-white/20"></span>
              </div>
            </div>

            <div className="grid grid-cols-1 gap-4">
              {ELECTRICAL_TEMPLATES.map((tmpl, idx) => (
                <button key={idx} onClick={() => handleSendMessage(tmpl)} className={`text-left p-5 rounded-3xl border-2 transition-all hover:translate-y-[-2px] group ${theme === 'dark' ? 'bg-white/5 border-white/5 hover:border-white/20' : 'bg-white border-gray-50 shadow-sm'}`}>
                  <div className="flex items-center gap-5">
                    <div className="w-10 h-10 rounded-2xl flex items-center justify-center transition-all shadow-inner" style={{ backgroundColor: `${activeColor.hex}15`, color: activeColor.hex }}>⚡</div>
                    <span className="font-semibold text-[14px] opacity-80 group-hover:opacity-100">{tmpl}</span>
                  </div>
                </button>
              ))}
            </div>
          </div>
        )}

        {messages.map((msg) => (
          <div key={msg.id} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'} animate-in fade-in slide-in-from-bottom-4 duration-500`}>
            <div className={`max-w-[90%] p-6 rounded-[2.5rem] shadow-2xl relative transition-all ${msg.role === 'user' ? (theme === 'dark' ? 'bg-white/5 border border-white/10' : 'bg-gray-100 border-none') : (theme === 'dark' ? 'bg-black/50 border border-white/5 backdrop-blur-md' : 'bg-white border-gray-200')}`}>
              {msg.attachments?.map((att, i) => (
                <img key={i} src={att.data} className={`w-full rounded-3xl mb-5 border-2 border-white/5 shadow-2xl ${msg.isImage ? 'h-auto max-h-[300px]' : 'h-32 object-cover'}`} />
              ))}

              <div className={`bot-message text-[16px] leading-relaxed ${msg.role === 'assistant' ? '' : 'font-semibold'}`} 
                   dangerouslySetInnerHTML={{ __html: msg.content }}>
              </div>

              {msg.role === 'assistant' && (
                <div className="mt-5 flex items-center gap-6 opacity-40 border-t border-white/5 pt-4">
                  <button onClick={() => handleListen(msg.content)} className="flex items-center gap-2 text-[10px] font-bold uppercase font-futuristic hover:opacity-100 transition-all" style={{ color: activeColor.hex }}>
                    Listen Signal
                  </button>
                </div>
              )}
            </div>
          </div>
        ))}
      </main>

      {/* Input Module - Beautiful, Glowing, Animated */}
      <div className={`relative z-30 px-6 pt-4 pb-16 transition-colors duration-500`}>
        <div className={`flex items-center gap-4 p-2 pl-4 rounded-[2.5rem] border-2 transition-all duration-300 input-glow ${theme === 'dark' ? 'bg-[#111] border-white/10' : 'bg-white border-gray-100 shadow-xl'}`}>
          <button onClick={() => fileInputRef.current?.click()} className="p-2 transition-all hover:rotate-12" style={{ color: activeColor.hex }}>
            <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M15.172 7l-6.586 6.586a2 2 0 102.828 2.828l6.414-6.586a4 4 0 00-5.656-5.656l-6.415 6.585a6 6 0 108.486 8.486L20.5 13" strokeWidth={2}/></svg>
            <input type="file" ref={fileInputRef} onChange={(e) => {
               const f = e.target.files?.[0];
               if(f) { const r = new FileReader(); r.onloadend = () => setPendingAttachments(p => [...p, { data: r.result as string, mimeType: f.type }]); r.readAsDataURL(f); }
            }} hidden />
          </button>

          <input 
            value={inputValue} 
            onChange={e => setInputValue(e.target.value)}
            onKeyDown={e => e.key === 'Enter' && handleSendMessage()}
            placeholder={t.inputHint}
            className={`flex-1 py-3 bg-transparent text-[15px] outline-none placeholder:opacity-30 ${theme === 'dark' ? 'text-white' : 'text-black'}`}
          />

          <button 
            onClick={() => handleSendMessage()}
            className={`w-12 h-12 flex items-center justify-center rounded-full transition-all duration-300 shadow-lg active:scale-90 group`}
            style={{ backgroundColor: activeColor.hex, boxShadow: `0 0 20px ${activeColor.shadow}` }}
          >
            <svg className="w-6 h-6 text-black group-hover:translate-x-0.5 group-hover:translate-y-[-0.5px] transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M13 10V3L4 14h7v7l9-11h-7z" strokeWidth={3}/></svg>
          </button>
        </div>
      </div>

      {/* Small Glowing Footer - Professional Size */}
      <footer className={`absolute bottom-0 left-0 w-full z-40 px-8 py-3 flex items-center justify-between border-t transition-all ${theme === 'dark' ? 'bg-black border-white/5' : 'bg-white border-gray-100'}`}>
         <div className="flex items-center gap-3 opacity-60 hover:opacity-100 transition-opacity">
            <div className="w-1.5 h-1.5 rounded-full animate-pulse shadow-[0_0_8px_currentColor]" style={{ backgroundColor: activeColor.hex, color: activeColor.hex }}></div>
            <span className="text-[10px] font-bold tracking-[0.2em] uppercase">{t.created}</span>
         </div>
         <a 
            href="https://www.facebook.com/share/1HnU5FCMGs/" 
            target="_blank" 
            rel="noopener noreferrer"
            className="p-1.5 rounded-lg transition-all hover:scale-110 active:scale-95 border"
            style={{ color: activeColor.hex, backgroundColor: `${activeColor.hex}0a`, borderColor: `${activeColor.hex}22` }}
          >
            <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 24 24"><path d="M24 12.073c0-6.627-5.373-12-12-12s-12 5.373-12 12c0 5.99 4.388 10.954 10.125 11.854v-8.385H7.078v-3.47h3.047V9.43c0-3.007 1.792-4.669 4.533-4.669 1.312 0 2.686.235 2.686.235v2.953H15.83c-1.491 0-1.956.925-1.956 1.874v2.25h3.328l-.532 3.47h-2.796v8.385C19.612 23.027 24 18.062 24 12.073z"/></svg>
          </a>
      </footer>

      {/* Settings Modal - Modernized */}
      {showSettings && (
        <div className="absolute inset-0 z-[120] flex items-end animate-in slide-in-from-bottom-full duration-500">
          <div className="w-full h-3/4 bg-[#0a0a0f] rounded-t-[4rem] p-10 border-t border-white/10 shadow-[0_-30px_100px_rgba(0,0,0,0.8)] overflow-y-auto">
            <div className="w-12 h-1.5 bg-white/10 rounded-full mx-auto mb-10"></div>
            <div className="flex justify-between items-center mb-12">
              <h3 className="font-futuristic tracking-[0.3em] text-sm uppercase" style={{ color: activeColor.hex }}>{t.settings}</h3>
              <button onClick={() => setShowSettings(false)} className="opacity-40 hover:opacity-100 transition-all"><svg className="w-8 h-8" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M6 18L18 6M6 6l12 12" strokeWidth={1.5}/></svg></button>
            </div>

            <div className="space-y-12">
              {/* Color Core Selector */}
              <div className="space-y-5">
                <span className="text-[11px] font-bold uppercase tracking-widest opacity-40">{t.color}</span>
                <div className="flex justify-between items-center bg-black/50 p-4 rounded-3xl border border-white/5">
                  {(Object.keys(COLOR_THEMES) as PrimaryColor[]).map(c => (
                    <button 
                      key={c}
                      onClick={() => setPrimaryColor(c)}
                      className={`w-10 h-10 rounded-full border-2 transition-all hover:scale-125 ${primaryColor === c ? 'border-white' : 'border-transparent'}`}
                      style={{ backgroundColor: COLOR_THEMES[c].hex, boxShadow: primaryColor === c ? `0 0 15px ${COLOR_THEMES[c].hex}` : '' }}
                    ></button>
                  ))}
                </div>
              </div>

              {/* Theme Toggle */}
              <div className="space-y-5">
                <span className="text-[11px] font-bold uppercase tracking-widest opacity-40">{t.theme}</span>
                <div className="grid grid-cols-2 bg-black/50 p-2 rounded-2xl border border-white/5">
                  <button onClick={() => setTheme('dark')} className={`py-3 rounded-xl text-[12px] font-bold transition-all ${theme === 'dark' ? 'bg-white/10 text-white' : 'opacity-20'}`}>DARK CORE</button>
                  <button onClick={() => setTheme('light')} className={`py-3 rounded-xl text-[12px] font-bold transition-all ${theme === 'light' ? 'bg-white text-black' : 'opacity-20'}`}>LIGHT CORE</button>
                </div>
              </div>

              {/* Language Selector */}
              <div className="space-y-5">
                <span className="text-[11px] font-bold uppercase tracking-widest opacity-40">{t.lang}</span>
                <div className="grid grid-cols-2 gap-3">
                  {SUPPORTED_LANGUAGES.map(lang => (
                    <button key={lang.code} onClick={() => setAppLang(lang.code)} className={`py-3 rounded-2xl text-[12px] font-bold border-2 transition-all ${appLang === lang.code ? 'border-white/20 bg-white/5' : 'border-transparent opacity-30 hover:opacity-60'}`}>{lang.name}</button>
                  ))}
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

